"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[105545],{144695:e=>{e.exports=JSON.parse('{"tag":{"label":"consumable","permalink":"/dst-api-webdocs/docs/tags/consumable","allTagsPath":"/dst-api-webdocs/docs/tags","count":93,"items":[{"id":"game-scripts/prefabs/antchovies","title":"Antchovies","description":"A prefabricated food item representing a tiny, shelf-stable fish snack with negligible nutritional value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/antchovies"},{"id":"game-scripts/prefabs/balloonspeed","title":"Balloonspeed","description":"Manages the lifecycle, flight physics, and fuel-based speed progression of a floating balloon used as a consumable speed boost item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloonspeed"},{"id":"game-scripts/prefabs/bandage","title":"Bandage","description":"A consumable small item that heals a fixed amount of health when used by a player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bandage"},{"id":"game-scripts/prefabs/bandage_butterflywings","title":"Bandage Butterflywings","description":"A consumable item that restores health and sanity when used, requiring the \\"walter_camp_firstaid\\" skill to trigger the sanity bonus.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bandage_butterflywings"},{"id":"game-scripts/prefabs/batbat","title":"Batbat","description":"A consumable weapon item that deals damage on attack and drains health/sanity from valid targets on critical hits.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/batbat"},{"id":"game-scripts/prefabs/bathbomb","title":"Bathbomb","description":"A consumable item that provides fuel and can be burned, featuring perishable behavior and inventory compatibility.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bathbomb"},{"id":"game-scripts/prefabs/bernie_inactive","title":"Bernie Inactive","description":"Manages the dormant state and self-decay mechanics for Bernie the Beard, including fuel consumption, reanimation logic, and equippable behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_inactive"},{"id":"game-scripts/prefabs/blowdart","title":"Blowdart","description":"A throwable weapon prefabricated as a family of darts with distinct effects (sleep, fire, electric, or damage), designed for use by the player or walrus creatures in combat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart"},{"id":"game-scripts/prefabs/boatpatch","title":"Boatpatch","description":"A game entity component that enables repairs to damaged boats using consumable patch materials (wood or kelp), providing health restoration and related functional behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatpatch"},{"id":"game-scripts/prefabs/brush","title":"Brush","description":"A consumable tool that allows players to groom Beefalo, restoring sanity and providing temporary speed and warmth bonuses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/brush"},{"id":"game-scripts/prefabs/bugnet","title":"Bugnet","description":"A reusable tool-and-weapon item that captures insects and degrades after a fixed number of uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bugnet"},{"id":"game-scripts/prefabs/butter","title":"Butter","description":"A consumable food item that restores health and hunger, which slowly spoils into spoiled food over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/butter"},{"id":"game-scripts/prefabs/carnival_gametoken","title":"Carnival Gametoken","description":"A consumable and tradable game token used as bait in DST, featuring periodic visual sparkle effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_gametoken"},{"id":"game-scripts/prefabs/charlierose","title":"Charlierose","description":"A one-time consumable flower item that shatters on drop and disappears after a short time unless picked up and placed in inventory.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/charlierose"},{"id":"game-scripts/prefabs/chum","title":"Chum","description":"A throwable fishing bait item that spawns chum or a green splash effect depending on terrain, and creates an AOE when thrown into ocean tiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chum"},{"id":"game-scripts/prefabs/compass","title":"Compass","description":"A consumable item that reveals map terrain and depletes over time when equipped, while also functioning as a basic melee weapon.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/compass"},{"id":"game-scripts/prefabs/cutgrass","title":"Cutgrass","description":"A small, renewable grass item that serves as food, fuel, and repair material for entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutgrass"},{"id":"game-scripts/prefabs/cutlichen","title":"Cutlichen","description":"A consumable food item that restores health and hunger but reduces sanity, and spoils over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutlichen"},{"id":"game-scripts/prefabs/deerclops_eyeball","title":"Deerclops Eyeball","description":"A consumable boss loot item dropped by Deerclops that restores health, hunger, and sanity when eaten.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deerclops_eyeball"},{"id":"game-scripts/prefabs/driedplants","title":"Driedplants","description":"Constructs dried vegetable items (e.g., dried petals, seeds) with consumable, fuel, and burnable properties, primarily used as loot, crafting ingredients, or cat toys.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/driedplants"},{"id":"game-scripts/prefabs/driftwood","title":"Driftwood","description":"A simple wood item that serves as fuel, edible material, repair resource, and waterproofer with zero effectiveness unless modified.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/driftwood"},{"id":"game-scripts/prefabs/featherpencil","title":"Featherpencil","description":"A consumable cat toy that breaks when drawn with and can be used as low-value fuel or igniter.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/featherpencil"},{"id":"game-scripts/prefabs/fence_rotator","title":"Fence Rotator","description":"A consumable tool used to rotate fences; equipped as an inventory item and decrements finite uses per rotation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fence_rotator"},{"id":"game-scripts/prefabs/firenettles","title":"Firenettles","description":"A consumable vegetable item that applies a temporary temperature-based debuff to non-plantkin eaters, which can be dried to produce a longer-lasting fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firenettles"},{"id":"game-scripts/prefabs/flint","title":"Flint","description":"A small, stackable item used as bait for moles and renewable debris, consumable to restore minimal hunger.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flint"},{"id":"game-scripts/prefabs/foliage","title":"Foliage","description":"A consumable, flammable inventory item used as fuel, food, or craftable ingredient that can dry into preserved form; primarily appears in the Quagmire game mode.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/foliage"},{"id":"game-scripts/prefabs/forgetmelots","title":"Forgetmelots","description":"A consumable vegetarian item that provides minimal sanity restoration, spoils quickly, and can be dried; also serves as a cat toy and vase decoration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/forgetmelots"},{"id":"game-scripts/prefabs/gears","title":"Gears","description":"A versatile consumable and repair item used for befriending clockwork creatures, restoring health/sanity/hunger, and repairing items in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gears"},{"id":"game-scripts/prefabs/ghostly_elixirs","title":"Ghostly Elixirs","description":"Creates consumable ghostly elixir items and their associated debuff components that apply temporary buffs to targets upon use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghostly_elixirs"},{"id":"game-scripts/components/ghostlyelixir","title":"Ghostlyelixir","description":"Handles the application of ghostly elixir effects to a target entity, consuming the item upon successful application.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostlyelixir"},{"id":"game-scripts/prefabs/glasscutter","title":"Glasscutter","description":"A consumable weapon prefab that deals damage with finite uses, deals bonus damage against shadow enemies, and provides visual feedback via equipped animations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glasscutter"},{"id":"game-scripts/prefabs/glommerwings","title":"Glommerwings","description":"A consumable item that provides medium-large fuel value and functions as burnable/propagator with hauntable properties in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommerwings"},{"id":"game-scripts/prefabs/goatmilk","title":"Goatmilk","description":"A consumable food item that restores health, hunger, and sanity, but spoils quickly and can be fed to cats.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/goatmilk"},{"id":"game-scripts/components/halloweenpotionmoon","title":"Halloweenpotionmoon","description":"Consumes a Halloween potion item to mutate a target entity via the HalloweenMoonMutable component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/halloweenpotionmoon"},{"id":"game-scripts/prefabs/hareball","title":"Hareball","description":"A consumable, renewable cat toy that perishes over time and can be ignited or thrown.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hareball"},{"id":"game-scripts/components/healer","title":"Healer","description":"Applies healing to a target entity and consumes the healer item upon use.","permalink":"/dst-api-webdocs/docs/game-scripts/components/healer"},{"id":"game-scripts/prefabs/hermitcrab_shell","title":"Hermitcrab Shell","description":"A consumable horn item that enables teleportation to the Hermit\'s house and has a secondary use for tending plants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrab_shell"},{"id":"game-scripts/prefabs/hermitcrabtea","title":"Hermitcrabtea","description":"Factory prefab generator for hermit crab tea items and their associated debuff effects, supporting reusable consumption, stat restoration, and temporary buffs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrabtea"},{"id":"game-scripts/prefabs/honey","title":"Honey","description":"A consumable food item that restores health and hunger, with slow perish rate and stackability.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/honey"},{"id":"game-scripts/prefabs/horn","title":"Horn","description":"A consumable instrument that\u53ec\u96c6s beefalo followers and tends farm plants when used by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/horn"},{"id":"game-scripts/prefabs/houndwhistle","title":"Houndwhistle","description":"A consumable tool that emits a whistle sound to attract hounds and wargs, adding them as followers to the user.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/houndwhistle"},{"id":"game-scripts/prefabs/inv_rocks_ice","title":"Inv Rocks Ice","description":"Represents a frozen ice rock that provides health, moisture, cooling effects, and can be used as a temporary water source; it melts over time or when exposed to fire.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/inv_rocks_ice"},{"id":"game-scripts/prefabs/ipecacsyrup","title":"Ipecacsyrup","description":"A consumable item that applies a debuff causing periodic poison damage and poop spawning over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ipecacsyrup"},{"id":"game-scripts/prefabs/lifeinjector","title":"Lifeinjector","description":"A consumable inventory item that restores health to the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lifeinjector"},{"id":"game-scripts/prefabs/mandrake_inactive","title":"Mandrake Inactive","description":"Represents an inactive mandrake plant prefab that becomes edible and triggers sleep effects when eaten raw or cooked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mandrake_inactive"},{"id":"game-scripts/prefabs/manrabbit_tail","title":"Manrabbit Tail","description":"A consumable food item dropped by Man Rabbits that serves as a cat toy and cannot be eaten by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/manrabbit_tail"},{"id":"game-scripts/components/maxhealer","title":"Maxhealer","description":"Applies a health penalty reduction to a target entity when consumed, typically used for revive-like consumable items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maxhealer"},{"id":"game-scripts/prefabs/milkywhites","title":"Milkywhites","description":"A consumable cat food item that restores health and hunger but reduces sanity, and spoil over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/milkywhites"},{"id":"game-scripts/prefabs/minotaurhorn","title":"Minotaurhorn","description":"A consumable meat item that restores health, hunger, and reduces sanity when eaten.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/minotaurhorn"},{"id":"game-scripts/prefabs/moonbutterflywings","title":"Moonbutterflywings","description":"A consumable inventory item that restores health, hunger, and sanity when eaten, but spoils quickly.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonbutterflywings"},{"id":"game-scripts/prefabs/moonrocknugget","title":"Moonrocknugget","description":"Prefab for a small, reusable crafting material that can be consumed for minimal nutrition, used in repairs, and dropped as loot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonrocknugget"},{"id":"game-scripts/prefabs/mosquitomermsalve","title":"Mosquitomermsalve","description":"A consumable item that heals merms and Wurt when applied, with enhanced healing and a debuff effect for Wurt if the appropriate skill is activated.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitomermsalve"},{"id":"game-scripts/prefabs/mosquitomusk","title":"Mosquitomusk","description":"A consumable inventory item that spoils over time and can be repaired with vitae material; used as bait for mosquito-based mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitomusk"},{"id":"game-scripts/prefabs/mosquitosack","title":"Mosquitosack","description":"A consumable inventory item that heals the user and repairs items while also acting as a combustible fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitosack"},{"id":"game-scripts/prefabs/nightsword","title":"Nightsword","description":"A consumable weapon that deals shadow damage and loses one use each time it is swung.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightsword"},{"id":"game-scripts/prefabs/palmcone_scale","title":"Palmcone Scale","description":"A consumable fuel item used for campfires and related ignition sources, providing moderate fuel value and burn duration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/palmcone_scale"},{"id":"game-scripts/prefabs/petals","title":"Petals","description":"A plant-based consumable item that can be dried into a different product and haunts under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petals"},{"id":"game-scripts/prefabs/petals_evil","title":"Petals Evil","description":"A perishable, dryable, and consumable item that grants sanity loss; used as a crafting component or food source with negative effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petals_evil"},{"id":"game-scripts/prefabs/phlegm","title":"Phlegm","description":"A consumable item that restores hunger and sanity but provides no health.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/phlegm"},{"id":"game-scripts/prefabs/pig_coin","title":"Pig Coin","description":"A consumable item that, when used, spawns a random Pig Elite Fighter as a follower and removes itself from play.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pig_coin"},{"id":"game-scripts/prefabs/pigskin","title":"Pigskin","description":"A consumable meat item that can be stacked, burned, and traded for gold, belonging to the \\"horrible\\" food category.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigskin"},{"id":"game-scripts/prefabs/pocket_scale","title":"Pocket Scale","description":"A consumable item that weighs fish and degrades with use, eventually destroying itself.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocket_scale"},{"id":"game-scripts/prefabs/purebrilliance","title":"Purebrilliance","description":"A consumable item that casts a wurt lunar spell, applying debuffs and triggering cheer events on nearby lunar minion followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/purebrilliance"},{"id":"game-scripts/prefabs/quagmire_sap","title":"Quagmire Sap","description":"A consumable sap item used in Quagmire recipes; spoils over time into a separate prefabs variant.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_sap"},{"id":"game-scripts/prefabs/rabbitkinghorn","title":"Rabbitkinghorn","description":"A consumable musical instrument that summons a rabbit king chest when used; tracks usage and validates spawn locations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbitkinghorn"},{"id":"game-scripts/prefabs/rabbitkingspear","title":"Rabbitkingspear","description":"A usable weapon item that grants sanity restoration against manrabbit targets and degrades after repeated use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbitkingspear"},{"id":"game-scripts/prefabs/refined_dust","title":"Refined Dust","description":"A small consumable elemental item that provides minimal hunger restoration and can be traded to rock-based entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/refined_dust"},{"id":"game-scripts/prefabs/royal_jelly","title":"Royal Jelly","description":"A consumable food item that restores health, hunger, and sanity; has a moderate perish time and can be stacked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/royal_jelly"},{"id":"game-scripts/prefabs/ruins_bat","title":"Ruins Bat","description":"A consumable equippable weapon that allows the player to summon shadow tentacles on attack, with a limited number of uses and shadow level scaling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruins_bat"},{"id":"game-scripts/prefabs/scandata","title":"Scandata","description":"A small, stackable consumable item used in Don\'t Starve Together for scanning or detecting entities and environmental data.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/scandata"},{"id":"game-scripts/prefabs/shadow_battleaxe","title":"Shadow Battleaxe","description":"A leveled, sentient weapon that evolves through epic creature kills, providing life steal, planar damage, and dynamic chat behavior while requiring hunger management and durability tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_battleaxe"},{"id":"game-scripts/prefabs/shadowheart_infused","title":"Shadowheart Infused","description":"A consumable item that provides a temporary sanity boost and emits a moderate sanity aura while held or carried.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowheart_infused"},{"id":"game-scripts/prefabs/spear","title":"Spear","description":"A consumable spear weapon with limited durability that deals fixed damage and supports skin overrides on equip/unequip.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spear"},{"id":"game-scripts/prefabs/spider_healer_item","title":"Spider Healer Item","description":"A consumable item that heals the Spider Whisperer and nearby spiders when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_healer_item"},{"id":"game-scripts/prefabs/spider_mutators","title":"Spider Mutators","description":"Generates prefabs for spider mutator items, each representing a specific spider subtype and enabling mutation of spider entities when consumed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_mutators"},{"id":"game-scripts/prefabs/spider_repellent","title":"Spider Repellent","description":"A consumable item that repels spiders while reducing stack usage over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_repellent"},{"id":"game-scripts/prefabs/spider_whistle","title":"Spider Whistle","description":"A consumable item that summons spiders from dens and wakes up sleeping spiders within range, while granting temporary buffs to nearby spider followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_whistle"},{"id":"game-scripts/prefabs/spiderden_bedazzler","title":"Spiderden Bedazzler","description":"A single-use consumable item that applies a bedazzling buff to a target upon use, designed for spider-related gameplay interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spiderden_bedazzler"},{"id":"game-scripts/prefabs/spidergland","title":"Spidergland","description":"A consumable inventory item that restores a moderate amount of health when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spidergland"},{"id":"game-scripts/prefabs/staff_tornado","title":"Staff Tornado","description":"A consumable weapon that spawns a tornado entity targeting an enemy, with limited uses and integration into the spellcasting and equippable systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/staff_tornado"},{"id":"game-scripts/prefabs/stash_map","title":"Stash Map","description":"A consumable map item that reveals the current stash location when used, and destroys itself after revealing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stash_map"},{"id":"game-scripts/prefabs/tentaclespike","title":"Tentaclespike","description":"A consumable weapon item that deals damage and degrades after a fixed number of uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tentaclespike"},{"id":"game-scripts/prefabs/thulecite","title":"Thulecite","description":"A reusable crafting material that repairs tools and structures, and can be consumed for minimal sustenance.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thulecite"},{"id":"game-scripts/prefabs/tillweedsalve","title":"Tillweedsalve","description":"A consumable healing item that applies a debuff-based regenerative effect to living targets over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tillweedsalve"},{"id":"game-scripts/prefabs/tree_rock_seed","title":"Tree Rock Seed","description":"A consumable item that, when deployed, grows into a tree_rock_sapling and replaces perishable spoilage with spoiled_food.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tree_rock_seed"},{"id":"game-scripts/prefabs/walrus_tusk","title":"Walrus Tusk","description":"A stackable inventory item prefab used for crafting and trading, typically obtained from walruses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/walrus_tusk"},{"id":"game-scripts/prefabs/wereitems","title":"Wereitems","description":"Defines prefabs for were-beast-specific food items (beaver, moose, goose) that behave as hazardous, meat-based consumables with cursed effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wereitems"},{"id":"game-scripts/prefabs/wintersfeastfuel","title":"Wintersfeastfuel","description":"A consumable inventory item that grants no nutritional or health benefits but triggers a talker-equipped eater to speak a seasonal phrase upon consumption.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastfuel"},{"id":"game-scripts/prefabs/woby_treat","title":"Woby Treat","description":"A consumable meat item that restores minimal hunger and health but reduces sanity; used as pet food or quick bait.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/woby_treat"},{"id":"game-scripts/prefabs/wormlight","title":"Wormlight","description":"Manages the lifecycle and visual effects of a consumable light source that transfers to a player or creature upon eating, providing light while it lasts before extinguishing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormlight"},{"id":"game-scripts/prefabs/yotb_blueprints","title":"Yotb Blueprints","description":"Creates consumable blueprint prefabs that, when used, spawn and fling a specific cosmetic Beefalo doll variant.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_blueprints"},{"id":"game-scripts/prefabs/yoth_knightstick","title":"Yoth Knightstick","description":"A consumable melee weapon that deals damage and burns fuel while the wielder moves forward.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yoth_knightstick"},{"id":"game-scripts/prefabs/yoth_lance","title":"Yoth Lance","description":"A consumable ranged weapon component that provides melee combat functionality with lance-specific jousting mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yoth_lance"}],"unlisted":false}}')}}]);